UPDATE vehicles v
SET imagen_principal = mi.img_url
FROM mongo_images mi
WHERE LOWER(v.marca) = mi.brand
  AND LOWER(v.modelo) = mi.model
  AND v.año_matriculacion = mi.year
  AND (v.imagen_principal IS NULL OR v.imagen_principal = '');